INSERT INTO `highline` (`id`, `typ`, `uzivatel_id`, `jmeno`, `delka`, `vyska`, `stat`, `oblast`, `kraj`, `gps`, `hodnoceni`, `kotveni`, `info`, `pointOneInfo`, `pointTwoInfo`, `autor`, `datum`, `lat`, `lng`, `parking_id`, `point1_id`, `point2_id`, `nameHistory`, `timeApproach`, `timeTensioning`) VALUES
(31,	2,	1,	'Planet Slackturn',	38,	20,	'Česká republika',	'Ostrov',	'Ústecký',	'(50.799432179940226, 14.055445790290833)',	3,	'3',	'                        ',	NULL,	NULL,	'',	'2009-05-02',	'50.799432179940226',	'14.055445790290833',	NULL,	1,	NULL,	NULL,	NULL,	NULL),
(32,	1,	1,	'Bišík',	8,	10,	'Česká republika',	'Bišík',	'Královéhradecký',	'(50.57167464639518, 16.140616536140442)',	2,	'3',	'                                                      ',	NULL,	NULL,	'',	'2007-08-12',	'50.57167464639518',	'16.140616536140442',	NULL,	2,	NULL,	NULL,	NULL,	NULL),
(33,	1,	1,	'Green Air line',	23,	20,	'Česká republika',	'Bišík',	'Královéhradecký',	'(50.57241396147993, 16.142217814922333)',	3,	'3',	'',	NULL,	NULL,	'',	'2008-08-04',	'50.57241396147993',	'16.142217814922333',	NULL,	3,	NULL,	NULL,	NULL,	NULL),
(34,	0,	1,	'Cimbuří-Cimbuline',	25,	20,	'Česká republika',	'Jizerské hory',	'Liberecký',	'(50.85641900198966, 15.216912031173706)',	4,	'2',	'<p>Prvn&iacute; skutečn&aacute; HL v Česku. Na podzim 2007 ji jako prvn&iacute; a jedinej pře&scaron;el Stefan Junghannss. My ostatn&iacute; jsme si museli rok počkat, ale st&aacute;lo to za to! Nově navrt&aacute;no na obou stran&aacute;ch kotven&iacute;!</p>\n',	'',	'',	'kolouch',	'2010-07-20',	'50.85641900198966',	'15.216912031173706',	152,	4,	151,	'',	NULL,	NULL),
(35,	0,	1,	'Ořešník',	22,	15,	'Česká republika',	'Jizerky',	'Liberecký',	'(50.860665321940225, 15.187810063362122)',	3,	'23',	'<p>Na obou stran&aacute;ch lepen&eacute; z&aacute;vitov&eacute; tyče průměr 12 mm celkem 5 kusů.Oka (plakety) nutno přin&eacute;st s sebou.</p>\n',	'',	'',	'kolouch',	'2009-08-20',	'50.860665321940225',	'15.187810063362122',	161,	5,	160,	'',	NULL,	NULL),
(36,	0,	1,	'Alter Weg',	15,	15,	'Česká republika',	'Ostrov',	'Ústecký',	'(50.79927621619304, 14.055853486061096)',	1,	'1',	'<p>Prvn&iacute; ofici&aacute;ln&iacute; highline v Česku.Přes svoj&iacute; nevelkou d&eacute;lku a v&yacute;&scaron;ku je ov&scaron;en velice nebezpečn&aacute;, zvl&aacute;&scaron;ť na kraj&iacute;ch může po p&aacute;du do odsedky doj&iacute;t ke kontaktu se sk&aacute;lou. Vzhledem k jej&iacute; snadn&eacute; dostupnosti a rychl&yacute; mont&aacute;ži l&aacute;k&aacute; k n&aacute;cviku pro hajlajnov&eacute; zač&aacute;tečn&iacute;ky. Doporučuju proto použ&iacute;vat přilbu a nastupovat v bezpečn&yacute; vzd&aacute;lenosti od okraje.</p>\n',	'',	'',	'Kolouch',	'2007-07-20',	'50.79927621619304',	'14.055853486061096',	157,	6,	156,	'Smolda tuhle lajnu napínal s Jelenem jako jednu z prvních hajlajn v ČR. První opakování a první FM bylo v roce 2008. \nNázev Alter Weg (Stará cesta) koresponduje s lezeckou tradicí Ostrova, kdy většina prvních výstupů na věž nesla právě toto jméno. (Q)',	15,	60),
(37,	1,	1,	'Nad Bivakem',	26,	20,	'Česká republika',	'Ostrov',	'Ústecký',	'(50.80101975955313, 14.0541522949934)',	2,	'13',	'      Poměrně složitá montáž na masívu vyžaduje jednak použití velkého množství materiálu na obvázání více slabých břízek a taky jeden megawoodhex- kus špalku- k dokotvení lajny na pevno ke skále, aby se lajna při pádech do odsedky nepředřela.\r\n  \r\n  ',	NULL,	NULL,	'kolouch',	'2010-04-16',	'50.80101975955313',	'14.0541522949934',	NULL,	7,	NULL,	NULL,	NULL,	NULL),
(38,	1,	1,	'Sváteční',	20,	13,	'Česká republika',	'Sloup v Čechách',	'Liberecký',	'(50.730153448657894, 14.586289823055267)',	2,	'1',	'                                          ',	NULL,	NULL,	'Kajoch',	'2010-03-07',	'50.730153448657894',	'14.586289823055267',	NULL,	8,	NULL,	NULL,	NULL,	NULL),
(39,	0,	1,	'Stoletá Doga',	18,	20,	'Česká republika',	'Tisá',	'Ústecký',	'(50.77957991567926, 14.047600328922272)',	3,	'13',	'<p>Lajna natažen&aacute; u př&iacute;ležitosti st&eacute;ho v&yacute;roč&iacute; v&yacute;stupu na jednu z dominant T&iacute;s&eacute;- Dogu. Vcelku snadn&aacute; mont&aacute;ž. Nejlehč&iacute; cestou, kterou lze na Dogu vystoupit je pětka z n&aacute;horn&iacute; strany. !!! Nekotvit lajnu pouze za prvn&iacute; dva kameny, ale obhodit cel&yacute; vrchol. Prvn&iacute; dva kameny se h&yacute;bou !!!</p>\n',	'',	'',	'kolouch',	'2007-08-20',	'50.77957991567926',	'14.047600328922272',	169,	9,	168,	'',	0,	0),
(40,	1,	1,	'Kinder highline',	8,	20,	'Česká republika',	'Osrtov',	'Ústecký',	'(50.80111553812495, 14.054127484560013)',	2,	'13',	'      \r\n  Názvem hajlajna pro děti.Ovšem opak je pravdou. Na věž je třeba překočit dvojkovým přeskokem, k montáži je třeba mrtě matroše a bandáže + bouldermatka. Těch pár kroků nestojí za tu námahu, ale lajna bezesporu patří k historii hajaljningu v česku. Never more!    \r\n    ',	NULL,	NULL,	'kolouch',	'2008-05-02',	'50.80111553812495',	'14.054127484560013',	NULL,	10,	NULL,	NULL,	NULL,	NULL),
(41,	3,	1,	'Kongolajna',	29,	12,	'Česká republika',	'jizerské hory',	'Liberecký',	'(50.87652972706758, 15.180771946907043)',	2,	'1',	'                      \r\n      \r\n  Městská HL v Hejnicích  u mostu přes řeku Smědou u hospody Kongo. Rychlá montáž na jedné straně za strom , na druhé za sloup. Pozor na projíždějící auta po mostu a na plot u sloupu- nepoškodit.    \r\n    \r\n            ',	NULL,	NULL,	'kolouch',	'2010-06-13',	'50.87652972706758',	'15.180771946907043',	NULL,	11,	NULL,	NULL,	NULL,	NULL),
