(191,	0,	149,	'Zub času',	53,	20,	'čr',	'Pantheon - Malá skála',	'český ráj',	'',	0,	'3',	'<p>Hajlajna na Pantheonu. Kotven&iacute; za uzel ve stěně a obhoz. prvn&iacute; tahal Kwjet&aacute;k v roce 2012.</p>\n',	'',	'',	'Kwjet',	'2012-10-01',	NULL,	NULL,	392,	390,	391,	'',	30,	120),
