(265,	0,	868,	'Shining downstairs fish',	24,	28,	NULL,	NULL,	NULL,	NULL,	2,	NULL,	'<p>V&iacute;c info v čl&aacute;nku:&nbsp;<a href=\"http://g4gproject.blogspot.com/2012/08/hned-mi-bylo-jasne-ze-nemuzeme-nikam.html\" target=\"_blank\">http://g4gproject.blogspot.com/2012/08/hned-mi-bylo-jasne-ze-nemuzeme-nikam.html</a></p>\n',	'Kotvit za vzdálenější strom ve směru, zvednout přes strom na kraji. Cca 8m spansetu. Backup ze jeden ze stromů.',	'Strom, 2m spanset. Backup za vzdálenější strom.',	'Faith Dickey, Jelena Schardi, Ančee (G4G team)',	'2012-07-01',	NULL,	NULL,	441,	439,	440,	'',	15,	45),
